<?php
namespace App\Http\Controllers\Admin;
use App\Http\Controllers\Controller; use App\Http\Requests\Admin\StoreServiceRequest; use App\Http\Requests\Admin\UpdateServiceRequest; use App\Models\Service; use App\Services\FileUploadService; use Illuminate\Http\RedirectResponse; use Illuminate\Http\Request; use Illuminate\Support\Facades\Cache; use Illuminate\View\View;
class ServiceController extends Controller { public function index(Request $request): View { $items=Service::query()->when($request->filled('search'),fn($q)=>$q->where(fn($qq)=>$qq->where('title','like','%'.$request->search.'%')->orWhere('slug','like','%'.$request->search.'%')->orWhere('short_description','like','%'.$request->search.'%')))->when($request->filled('status'),fn($q)=>$q->where('status',(bool)$request->integer('status')))->ordered()->paginate(15)->withQueryString(); return view('admin.pages.services.index',compact('items')); } public function create(): View { return view('admin.pages.services.form',['item'=>new Service()]); } public function store(StoreServiceRequest $request, FileUploadService $uploader): RedirectResponse { $data=$this->payload($request->validated()); $data['image']=$uploader->replace($request->file('image'),null,'uploads/services'); Service::create($data); $this->clearCache(); return redirect()->route('admin.services.index')->with('success','Service created successfully.'); } public function edit(Service $service): View { return view('admin.pages.services.form',['item'=>$service]); } public function update(UpdateServiceRequest $request, Service $service, FileUploadService $uploader): RedirectResponse { $data=$this->payload($request->validated()); $data['image']=$uploader->replace($request->file('image'),$service->image,'uploads/services'); $service->update($data); $this->clearCache(); return redirect()->route('admin.services.index')->with('success','Service updated successfully.'); } public function destroy(Service $service): RedirectResponse { $service->delete(); $this->clearCache(); return back()->with('success','Service deleted successfully.'); } private function payload(array $data): array { $data['status']=(bool)($data['status']??false); $data['sort_order']=(int)($data['sort_order']??0); return $data; } private function clearCache(): void { foreach(['services_active_ordered','homepage_services_active'] as $key) Cache::forget($key); } }
